# risk_score.py — compute risk scores for all inventory entries

from dataclasses import dataclass
from typing import List

EXPOSURE_SCORES = {
    "external": 40,
    "internal": 20,
    "infra":    10,
    "dev_only":  0,
}

@dataclass
class RiskScore:
    package: str
    version: str
    exposure_score: int
    cve_score: int
    staleness_score: int

    @property
    def total(self) -> int:
        return self.exposure_score + self.cve_score + self.staleness_score

    @property
    def priority(self) -> str:
        if self.total >= 75: return "Critical"
        if self.total >= 50: return "High"
        if self.total >= 25: return "Medium"
        return "Low"

def compute_staleness_score(days_behind: int) -> int:
    if days_behind < 30:  return 0
    if days_behind < 90:  return 5
    if days_behind < 180: return 10
    return 20

def compute_cve_score(open_cves: List[dict]) -> int:
    total = sum(vuln.get("cvss", 0) for vuln in open_cves)
    return min(int(total), 40)

def score_dependency(dep: dict, classification: dict) -> RiskScore:
    category, exposure = classification.get(
        dep["name"].lower(), ("utility", "internal")
    )
    return RiskScore(
        package=dep["name"],
        version=dep["pinned_version"],
        exposure_score=EXPOSURE_SCORES.get(exposure, 10),
        cve_score=compute_cve_score(dep.get("open_cves", [])),
        staleness_score=compute_staleness_score(dep.get("days_behind_latest", 0)),
    )

def build_priority_queue(inventory: List[dict], classification: dict) -> List[RiskScore]:
    scores = [score_dependency(dep, classification) for dep in inventory
              if dep.get("production", True)]
    return sorted(scores, key=lambda s: s.total, reverse=True)
